}

glsl.fragment:
precision highp float;
varying vec2 vUv;
uniform float uTime;
uniform vec3 baseColor;
uniform vec3 warmColor;
uniform vec3 coolColor;
uniform float washScale;
uniform float fiberAmount;
uniform float vignette;
float hash(vec2 p){ return fract(sin(dot(p, vec2(127.1,311.7))) * 43758.5453123); }
float noise(vec2 p){
 vec2 i = floor(p), f = fract(p);
 float a = hash(i);
 float b = hash(i + vec2(1.0,0.0));
 float c = hash(i + vec2(0.0,1.0));
 float d = hash(i + vec2(1.0,1.0));
 vec2 u = f*f*(3.0-2.0*f);
 return mix(a,b,u.x) + (c-a)*u.y*(1.0-u.x) + (d-b)*u.x*u.y;
}
float fbm(vec2 p){
 float v = 0.0;
 float a = 0.5;
 for(int i=0;i<5;i++){
 v += a * noise(p);
 p = p * 2.0 + vec2(17.0, 9.0);
 a *= 0.5;
 }
 return v;
}
void main(){
 vec2 uv = vUv;
 vec2 p = (uv - 0.5) * vec2(1.0, 1.35);
 float wash = fbm(uv * washScale * 3.2 + vec2(0.0, 0.03 * uTime));
 float warmBand = smoothstep(-0.25, 0.45, 0.65 - p.y + 0.18 * noise(uv * 4.0));
 float coolBand = smoothstep(0.15, 0.95, p.y + 0.12 * noise(uv * 5.0 + 4.0));
 vec3 col = baseColor;
 col = mix(col, warmColor, 0.12 * warmBand);
 col = mix(col, coolColor, 0.05 * coolBand);
 col += (wash - 0.5) * 0.12;
 float fibers = noise(vec2(uv.x * 120.0, uv.y * 8.0)) * fiberAmount;
 col -= fibers;
 float vig = 1.0 - vignette * smoothstep(0.22, 0.92, length((uv - 0.5) * vec2(1.0, 1.2)));
 col *= vig;
 gl_FragColor = vec4(col, 1.0);
}

