glsl.fragment:
precision highp float;
varying vec2 vUv;
uniform vec3 bodyColor;
uniform vec3 rimColor;
uniform vec3 auraColor;
uniform float width;
uniform float height;
uniform float rimSoftness;
float sdVesica(vec2 p, float r, float d){
 p.x = abs(p.x);
 float b = sqrt(max(r*r - d*d, 0.0));
 return ((p.y - b) * d > p.x * b) ? length(p - vec2(0.0, b)) : length(p - vec2(-d, 0.0)) - r;
}
float noise(vec2 p){ return fract(sin(dot(p, vec2(41.0,289.0))) * 43758.5453); }
void main(){
 vec2 p = (vUv - 0.5) * vec2(1.0, 1.7);
 p.x /= width;
 p.y /= height;
 float d = sdVesica(p, 0.58, 0.18);
 float edge = smoothstep(rimSoftness, -rimSoftness, d);
 float rim = smoothstep(0.03, 0.0, abs(d));
 float innerWash = 0.5 + 0.5 * noise(vUv * 18.0);
 vec3 col = mix(vec3(0.0), bodyColor * (0.92 + 0.08 * innerWash), edge);
 col += rimColor * rim * 0.55;
 col += auraColor * smoothstep(0.2, -0.25, d) * 0.08;
 float fade = smoothstep(1.02, 0.76, abs(p.y));
 gl_FragColor = vec4(col, edge * fade);
}

