glsl.fragment:
precision highp float;
varying vec2 vUv;
uniform float uTime;
uniform vec3 warmColor;
uniform vec3 coolColor;
uniform vec3 goldColor;
uniform float amplitude;
uniform float speed;
uniform float thickness;
float lineBand(float d, float t){ return smoothstep(t, 0.0, abs(d)); }
float hash(vec2 p){ return fract(sin(dot(p, vec2(97.1,211.7))) * 43758.5453123); }
float n2(vec2 p){
 vec2 i = floor(p), f = fract(p);
 float a = hash(i), b = hash(i+vec2(1.0,0.0)), c = hash(i+vec2(0.0,1.0)), d = hash(i+vec2(1.0,1.0));
 vec2 u = f*f*(3.0-2.0*f);
 return mix(mix(a,b,u.x), mix(c,d,u.x), u.y);
}
void main(){
 vec2 uv = vUv;
 vec2 p = (uv - 0.5) * vec2(1.0, 1.7);
 float rise = uv.y;
 float wobA = sin(rise * 5.4 + 0.4) * amplitude + (n2(vec2(rise * 4.0, 1.2)) - 0.5) * 0.08;
 float wobB = sin(rise * 5.0 + 2.5) * amplitude + (n2(vec2(rise * 4.0, 3.1)) - 0.5) * 0.08;
 float xA = mix(-0.2, -0.02, smoothstep(0.1, 0.95, rise)) + wobA * (1.0 - rise * 0.55);
 float xB = mix(0.2, 0.02, smoothstep(0.1, 0.95, rise)) + wobB * (1.0 - rise * 0.55);
 float a = lineBand(p.x - xA, thickness * mix(1.3, 0.7, rise));
 float b = lineBand(p.x - xB, thickness * mix(1.3, 0.7, rise));
 float convergence = smoothstep(0.72, 0.98, rise) * exp(-abs(p.x) * 18.0);
 vec3 col = warmColor * a * 0.72 + coolColor * b * 0.6 + goldColor * convergence * 0.18;
 float alpha = clamp(max(a, b) * smoothstep(0.06, 0.22, rise) * (1.0 - smoothstep(0.98, 1.02, rise)), 0.0, 1.0);
 gl_FragColor = vec4(col, alpha);
}
